  --shadow-2xs: 0px 2px 0px 0px hsl(262, 83%, 58%, 0);
  --shadow-xs: 0px 2px 0px 0px hsl(262, 83%, 58%, 0);
  --shadow-sm: 0px 2px 0px 0px hsl(262, 83%, 58%, 0), 0px 1px 2px -1px hsl(262, 83%, 58%, 0);
  --shadow: 0px 2px 0px 0px hsl(262, 83%, 58%, 0), 0px 1px 2px -1px hsl(262, 83%, 58%, 0);
  --shadow-md: 0px 2px 0px 0px hsl(262, 83%, 58%, 0), 0px 2px 4px -1px hsl(262, 83%, 58%, 0);
  --shadow-lg: 0px 2px 0px 0px hsl(262, 83%, 58%, 0), 0px 4px 6px -1px hsl(262, 83%, 58%, 0);
  --shadow-xl: 0px 2px 0px 0px hsl(262, 83%, 58%, 0), 0px 8px 10px -1px hsl(262, 83%, 58%, 0);
