client/src/pages/style-quiz.tsx.content:
import { useState, useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { Progress } from "@/components/ui/progress";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import { useLocation } from "wouter";
import { ArrowLeft, ArrowRight, Sparkles, RefreshCw } from "lucide-react";
import { RotatingBackground } from "@/components/RotatingBackground";
import { type StyleProfile } from "@shared/schema";

const QUIZ_STEPS = [
  {
    id: "style",
    title: "Your Style",
    description: "Tell us about your fashion personality",
  },
  {
    id: "bodyType",
    title: "Body & Colors",
    description: "Help us find your perfect fit and palette",
  },
  {
    id: "lifestyle",
    title: "Lifestyle & Budget",
    description: "Match your wardrobe to your life",
  },
  {
    id: "firstOutfit",
    title: "First Outfit",
    description: "Choose what to generate first",
  },
];

export default function StyleQuiz() {
  const { user, isLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [, setLocation] = useLocation();

  const [currentStep, setCurrentStep] = useState(0);
  const [isEditing, setIsEditing] = useState(false);
  const [answers, setAnswers] = useState({
    personality: {} as Record<string, string>,
    bodyType: "",
    colorPreference: "",
    stylePreference: "", // Single selection for style preference
    clothingItems: [] as string[], // Keep for backward compatibility with database
    lifestyle: {} as Record<string, string>,
    budget: "",
    occasions: [] as string[], // Multi-select for occasions
  });

  // Fetch existing style profile
  const { data: existingProfile } = useQuery<StyleProfile>({
    queryKey: ["/api/style-profile"],
    enabled: !!user,
  });

  // Pre-fill form with existing profile data
  useEffect(() => {
    if (existingProfile && !isEditing) {
      // Parse arrays
      const colorPrefs = JSON.parse(existingProfile.colorPreferences || '[]');
      const stylePrefs = JSON.parse(existingProfile.stylePreferences || '[]');
      const occasions = JSON.parse(existingProfile.occasions || '[]');
      const clothingItems = JSON.parse(existingProfile.clothingItems || '[]');

      setAnswers({
        personality: JSON.parse(existingProfile.personality || '{}'),
        bodyType: existingProfile.bodyType || "",
        colorPreference: colorPrefs[0] || "",
        stylePreference: stylePrefs[0] || "", // Single selection
        clothingItems: clothingItems,
        lifestyle: JSON.parse(existingProfile.lifestyle || '{}'),
        budget: existingProfile.budget || "",
        occasions: occasions,
      });
      setIsEditing(true);
    }
  }, [existingProfile, isEditing]);

  const handleResetQuiz = () => {
    setAnswers({
      personality: {},
      bodyType: "",
      colorPreference: "",
      stylePreference: "",
      clothingItems: [],
      lifestyle: {},
      budget: "",
      occasions: [],
    });
    setCurrentStep(0);
    setIsEditing(false);
    toast({
      title: "Quiz Reset",
      description: "Start fresh with your style preferences!",
    });
  };

  const saveProfileMutation = useMutation({
    mutationFn: async (profileData: any) => {
      // First save the profile
      await apiRequest("POST", "/api/style-profile", profileData);

      // If this is a new profile (not editing) and occasions are selected, generate the first outfit
      if (!isEditing && answers.occasions.length > 0) {
        await apiRequest("POST", "/api/generate-outfits", {
          occasion: answers.occasions[0], // Use first selected occasion
          count: 1
        });
      }
    },
    onSuccess: () => {
      if (isEditing) {
        toast({
          title: "Style Profile Updated!",
          description: "Your preferences have been saved.",
        });
      } else {
        toast({
          title: "Profile Saved!",
          description: answers.occasions.length > 0 ? "Generating your first outfit..." : "Your style profile is ready.",
        });
      }
      queryClient.invalidateQueries({ queryKey: ["/api/style-profile"] });
      queryClient.invalidateQueries({ queryKey: ["/api/outfits"] });
      setLocation("/dashboard");
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to save profile. Please try again.",
        variant: "destructive",
      });
    },
  });

  if (isLoading) {
    return (
      <RotatingBackground>
        <div className="min-h-screen flex items-center justify-center">
          <div className="animate-spin w-8 h-8 border-4 border-purple-600 border-t-transparent rounded-full" />
        </div>
      </RotatingBackground>
    );
  }

  const handleNext = () => {
    if (currentStep < QUIZ_STEPS.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      handleSubmit();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    // Prepare profile data with multi-select arrays
    const profileData = {
      personality: JSON.stringify(answers.personality),
      bodyType: answers.bodyType,
      colorPreferences: JSON.stringify([answers.colorPreference].filter(Boolean)),
      stylePreferences: JSON.stringify([answers.stylePreference].filter(Boolean)),
      clothingItems: JSON.stringify(answers.clothingItems),
      lifestyle: JSON.stringify(answers.lifestyle),
      budget: answers.budget,
      occasions: JSON.stringify(answers.occasions),
      completed: true,
    };

    saveProfileMutation.mutate(profileData);
  };

  const updateAnswer = (field: string, value: any) => {
    setAnswers(prev => ({
      ...prev,
      [field]: value,
    }));
  };

  const updatePersonality = (trait: string, value: string) => {
    setAnswers(prev => ({
      ...prev,
      personality: {
        ...prev.personality,
        [trait]: value,
      },
    }));
  };

  const updateLifestyle = (aspect: string, value: string) => {
    setAnswers(prev => ({
      ...prev,
      lifestyle: {
        ...prev.lifestyle,
        [aspect]: value,
      },
    }));
  };

  // Toggle multi-select array items (for checkboxes)
  const toggleArrayItem = (field: 'clothingItems' | 'occasions', value: string) => {
    setAnswers(prev => {
      const currentArray = prev[field];
      const newArray = currentArray.includes(value)
        ? currentArray.filter((item: string) => item !== value)
        : [...currentArray, value];
      return {
        ...prev,
        [field]: newArray,
      };
    });
  };

  const progress = ((currentStep + 1) / QUIZ_STEPS.length) * 100;
  const currentStepData = QUIZ_STEPS[currentStep];

  return (
    <RotatingBackground className="py-8">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-white mb-4" data-testid="heading-quiz-title">
            {isEditing ? "Edit Your Style Profile" : "Style Discovery Quiz"}
          </h1>
          <div className="flex items-center justify-center mb-6">
            <Sparkles className="w-6 h-6 text-purple-400 mr-2" />
            <span className="text-gray-300">Step {currentStep + 1} of {QUIZ_STEPS.length}</span>
          </div>
          <Progress value={progress} className="max-w-md mx-auto" data-testid="progress-quiz" />

          {/* Reset Button for users with existing profiles */}
          {existingProfile && (
            <Button 
              variant="outline"
              onClick={handleResetQuiz}
              className="mt-4 border-white/20 text-white hover:bg-white/10"
              data-testid="button-reset-quiz"
            >
              <RefreshCw className="w-4 h-4 mr-2" />
              Reset Quiz
            </Button>
          )}
        </div>

        <Card className="bg-white/10 backdrop-blur-sm border-white/20" data-testid="card-quiz-step">
          <CardHeader>
            <CardTitle className="text-white text-2xl text-center">
              {currentStepData.title}
            </CardTitle>
            <p className="text-gray-300 text-center" data-testid="text-step-description">
              {currentStepData.description}
            </p>
          </CardHeader>
          <CardContent className="p-8">
            {/* Step 1: Style Preference */}
            {currentStep === 0 && (
              <div className="space-y-6" data-testid="step-style">
                <div>
                  <Label className="text-white text-lg mb-4 block">How would you describe your style personality?</Label>
                  <RadioGroup value={answers.stylePreference} onValueChange={(value) => updateAnswer('stylePreference', value)}>
                    {['Classic & Timeless', 'Trendy & Fashion-Forward', 'Bohemian & Free-Spirited', 'Minimalist & Clean', 'Edgy & Bold', 'Casual & Comfortable', 'Professional & Polished', 'Artistic & Creative'].map((option) => (
                      <div key={option} className="flex items-center space-x-2" data-testid={`radio-style-${option.toLowerCase().replace(/[^a-z0-9]/g, '-')}`}>
                        <RadioGroupItem value={option} id={option} />
                        <Label htmlFor={option} className="text-gray-200 cursor-pointer">{option}</Label>
                      </div>
                    ))}
                  </RadioGroup>
                </div>
              </div>
            )}

            {/* Step 2: Body Type & Colors */}
            {currentStep === 1 && (
              <div className="space-y-6" data-testid="step-body-colors">
                <div>
                  <Label className="text-white text-lg mb-4 block">What's your body type?</Label>
                  <RadioGroup value={answers.bodyType} onValueChange={(value) => updateAnswer('bodyType', value)}>
                    {['Apple', 'Pear', 'Hourglass', 'Rectangle', 'Inverted Triangle', 'Prefer not to specify'].map((type) => (
                      <div key={type} className="flex items-center space-x-2" data-testid={`radio-body-type-${type.toLowerCase().replace(/\s/g, '-')}`}>
                        <RadioGroupItem value={type} id={type} />
                        <Label htmlFor={type} className="text-gray-200">{type}</Label>
                      </div>
                    ))}
                  </RadioGroup>
                </div>

                <div>
                  <Label className="text-white text-lg mb-4 block">What's your favorite color palette?</Label>
                  <RadioGroup value={answers.colorPreference} onValueChange={(value) => updateAnswer('colorPreference', value)}>
                    {['Neutral (Black, White, Gray)', 'Earth Tones (Brown, Beige, Tan)', 'Classic (Navy, White, Khaki)', 'Bold & Bright (Red, Yellow, Orange)', 'Cool Tones (Blue, Green, Purple)', 'Soft & Pastel (Pink, Lavender, Mint)'].map((color) => (
                      <div key={color} className="flex items-center space-x-2" data-testid={`radio-color-${color.toLowerCase().replace(/[^a-z0-9]/g, '-')}`}>
                        <RadioGroupItem value={color} id={color} />
                        <Label htmlFor={color} className="text-gray-200">{color}</Label>
                      </div>
                    ))}
                  </RadioGroup>
                </div>
              </div>
            )}

            {/* Step 3: Lifestyle & Budget */}
            {currentStep === 2 && (
              <div className="space-y-6" data-testid="step-lifestyle-budget">
                <div>
                  <Label className="text-white text-lg mb-4 block">What's your primary lifestyle?</Label>
                  <RadioGroup 
                    value={answers.lifestyle.work} 
                    onValueChange={(value) => updateLifestyle('work', value)}
                  >
                    {['Corporate Professional', 'Creative Professional', 'Student', 'Stay-at-home Parent', 'Active/Outdoors', 'Social Butterfly'].map((option) => (
                      <div key={option} className="flex items-center space-x-2" data-testid={`radio-work-${option.toLowerCase().replace(/[^a-z0-9]/g, '-')}`}>
                        <RadioGroupItem value={option} id={option} />
                        <Label htmlFor={option} className="text-gray-200">{option}</Label>
                      </div>
                    ))}
                  </RadioGroup>
                </div>
                <div>
                  <Label className="text-white text-lg mb-4 block">What's your typical clothing budget?</Label>
                  <RadioGroup value={answers.budget} onValueChange={(value) => updateAnswer('budget', value)}>
                    {['Under $50 per item', '$50-$100 per item', '$100-$200 per item', '$200-$500 per item', '$500+ per item'].map((option) => (
                      <div key={option} className="flex items-center space-x-2" data-testid={`radio-budget-${option.toLowerCase().replace(/[^a-z0-9]/g, '-')}`}>
                        <RadioGroupItem value={option} id={option} />
                        <Label htmlFor={option} className="text-gray-200">{option}</Label>
                      </div>
                    ))}
                  </RadioGroup>
                </div>
              </div>
            )}

            {/* Step 4: First Outfit Selection */}
            {currentStep === 3 && (
              <div className="space-y-6" data-testid="step-first-outfit">
                <div>
                  <Label className="text-white text-lg mb-4 block">Choose occasions for your outfits (Select all that apply)</Label>
                  <div className="space-y-3">
                    {[
                      { value: 'work', label: 'Work/Professional', icon: '💼' },
                      { value: 'casual', label: 'Casual Daily', icon: '👕' },
                      { value: 'date-night', label: 'Date Night', icon: '💕' },
                      { value: 'social-events', label: 'Social Events', icon: '🎉' },
                      { value: 'travel', label: 'Travel', icon: '✈️' },
                      { value: 'formal', label: 'Formal Events', icon: '🤵' },
                      { value: 'weekend', label: 'Weekend', icon: '🌞' },
                      { value: 'workout', label: 'Workout', icon: '💪' }
                    ].map((occasion) => {
                      const sanitizedId = `occasion-${occasion.value}`;
                      return (
                        <div key={occasion.value} className="flex items-center space-x-3" data-testid={`checkbox-${sanitizedId}`}>
                          <Checkbox 
                            id={sanitizedId}
                            checked={answers.occasions.includes(occasion.value)}
                            onCheckedChange={() => toggleArrayItem('occasions', occasion.value)}
                          />
                          <Label htmlFor={sanitizedId} className="text-gray-200 flex items-center cursor-pointer">
                            <span className="mr-2">{occasion.icon}</span>
                            {occasion.label}
                          </Label>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-6 p-4 bg-purple-500/10 rounded-lg border border-purple-400/20">
                    <p className="text-purple-200 text-sm">
                      💡 <strong>Your first outfit will be generated automatically!</strong> After that, you can create outfits for any occasion from your dashboard.
                    </p>
                  </div>
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Navigation */}
        <div className="flex justify-between mt-8">
          <Button 
            variant="outline" 
            onClick={handleBack}
            disabled={currentStep === 0}
            className="border-white/20 text-white hover:bg-white/10"
            data-testid="button-back"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back
          </Button>

          <Button 
            onClick={handleNext}
            disabled={saveProfileMutation.isPending}
            className="bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700 text-white"
            data-testid="button-next"
          >
            {saveProfileMutation.isPending ? (
              "Saving..."
            ) : currentStep === QUIZ_STEPS.length - 1 ? (
              "Complete Quiz"
            ) : (
              <>
                Next
                <ArrowRight className="w-4 h-4 ml-2" />
              </>
            )}
          </Button>
        </div>
      </div>
    </RotatingBackground>
  );
}

server/storage.ts.content:
import {
  users,
  styleProfiles,
  outfits,
  styleCollections,
  userPoints,
  shoppingAnalytics,
  type User,
  type UpsertUser,
  type StyleProfile,
  type InsertStyleProfile,
  type Outfit,
  type InsertOutfit,
  type StyleCollection,
  type InsertCollection,
  type UserPoints,
  type ShoppingAnalytics,
  type InsertShoppingAnalytics,
} from "@shared/schema";
import { db } from "./db";
import { eq, desc, isNull, isNotNull, and, lt, sql } from "drizzle-orm";

export interface IStorage {
  // User operations (IMPORTANT: mandatory for Replit Auth)
  getUser(id: string): Promise<User | undefined>;
  upsertUser(user: UpsertUser): Promise<User>;
  updateUserStripeInfo(userId: string, stripeCustomerId: string, stripeSubscriptionId: string): Promise<User>;

  // Style profile operations
  getStyleProfile(userId: string): Promise<StyleProfile | undefined>;
  createOrUpdateStyleProfile(profile: InsertStyleProfile): Promise<StyleProfile>;

  // Outfit operations
  getUserOutfits(userId: string): Promise<Outfit[]>;
  getUserDeletedOutfits(userId: string): Promise<Outfit[]>;
  getOutfit(id: string, userId: string): Promise<Outfit | undefined>;
  createOutfit(outfit: InsertOutfit): Promise<Outfit>;
  updateOutfit(id: string, updates: Partial<InsertOutfit>): Promise<Outfit>;
  updateOutfitImage(id: string, imageUrl: string, dalleUrl?: string): Promise<Outfit>;
  deleteOutfit(id: string): Promise<void>; // Soft delete
  permanentlyDeleteOutfit(id: string): Promise<void>; // Hard delete
  restoreOutfit(id: string): Promise<Outfit>;
  cleanupOldDeletedOutfits(): Promise<void>; // Remove outfits deleted over 30 days ago
  toggleFavoriteOutfit(id: string): Promise<Outfit>;

  // Collection operations
  getUserCollections(userId: string): Promise<StyleCollection[]>;
  createCollection(collection: InsertCollection): Promise<StyleCollection>;
  updateCollection(id: string, updates: Partial<InsertCollection>): Promise<StyleCollection>;
  deleteCollection(id: string): Promise<void>;

  // Points operations
  getUserPoints(userId: string): Promise<UserPoints | undefined>;
  updateUserPoints(userId: string, pointsToAdd: number): Promise<UserPoints>;
  initializeUserPoints(userId: string): Promise<UserPoints>;

  // Shopping analytics operations
  trackShoppingClick(analytics: InsertShoppingAnalytics): Promise<ShoppingAnalytics>;

  // Admin operations
  getAllUsers(): Promise<User[]>;
  getAllOutfits(): Promise<Outfit[]>;
  getAdminStats(): Promise<any>;
}

export class DatabaseStorage implements IStorage {
  // User operations
  async getUser(id: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.id, id));
    return user;
  }

  async upsertUser(userData: UpsertUser): Promise<User> {
    const [user] = await db
      .insert(users)
      .values(userData)
      .onConflictDoUpdate({
        target: users.id,
        set: {
          ...userData,
          updatedAt: new Date(),
        },
      })
      .returning();
    return user;
  }

  async updateUserStripeInfo(userId: string, stripeCustomerId: string, stripeSubscriptionId: string): Promise<User> {
    const [user] = await db
      .update(users)
      .set({
        stripeCustomerId,
        stripeSubscriptionId,
        subscriptionStatus: "premium",
        updatedAt: new Date(),
      })
      .where(eq(users.id, userId))
      .returning();
    return user;
  }

  // Style profile operations
  async getStyleProfile(userId: string): Promise<StyleProfile | undefined> {
    const [profile] = await db
      .select()
      .from(styleProfiles)
      .where(eq(styleProfiles.userId, userId));
    return profile;
  }

  async createOrUpdateStyleProfile(profile: InsertStyleProfile): Promise<StyleProfile> {
    const existing = await this.getStyleProfile(profile.userId);

    if (existing) {
      const [updated] = await db
        .update(styleProfiles)
        .set({
          ...profile,
          updatedAt: new Date(),
        })
        .where(eq(styleProfiles.userId, profile.userId))
        .returning();
      return updated;
    } else {
      const [created] = await db
        .insert(styleProfiles)
        .values(profile)
        .returning();
      return created;
    }
  }

  // Outfit operations
  async getUserOutfits(userId: string): Promise<Outfit[]> {
    return await db
      .select()
      .from(outfits)
      .where(and(
        eq(outfits.userId, userId),
        isNull(outfits.deletedAt)
      ))
      .orderBy(desc(outfits.createdAt));
  }

  async getUserDeletedOutfits(userId: string): Promise<Outfit[]> {
    return await db
      .select()
      .from(outfits)
      .where(and(
        eq(outfits.userId, userId),
        isNotNull(outfits.deletedAt)
      ))
      .orderBy(desc(outfits.deletedAt));
  }

  async getOutfit(id: string, userId: string): Promise<Outfit | undefined> {
    const [outfit] = await db
      .select()
      .from(outfits)
      .where(and(
        eq(outfits.id, id),
        eq(outfits.userId, userId)
      ));
    return outfit;
  }

  async createOutfit(outfit: InsertOutfit): Promise<Outfit> {
    const [created] = await db
      .insert(outfits)
      .values(outfit)
      .returning();
    return created;
  }

  async updateOutfit(id: string, updates: Partial<InsertOutfit>): Promise<Outfit> {
    const [updated] = await db
      .update(outfits)
      .set(updates)
      .where(eq(outfits.id, id))
      .returning();
    return updated;
  }

  async updateOutfitImage(id: string, imageUrl: string, dalleUrl?: string): Promise<Outfit> {
    const updateData: any = { imageUrl };
    if (dalleUrl) {
      updateData.dalleUrl = dalleUrl;
    }
    const [updated] = await db
      .update(outfits)
      .set(updateData)
      .where(eq(outfits.id, id))
      .returning();
    return updated;
  }

  async deleteOutfit(id: string): Promise<void> {
    // Soft delete by setting deletedAt timestamp
    await db
      .update(outfits)
      .set({ deletedAt: new Date() })
      .where(eq(outfits.id, id));
  }

  async permanentlyDeleteOutfit(id: string): Promise<void> {
    // Hard delete - actually remove from database
    await db.delete(outfits).where(eq(outfits.id, id));
  }

  async restoreOutfit(id: string): Promise<Outfit> {
    // Restore soft deleted outfit by clearing deletedAt
    const [restored] = await db
      .update(outfits)
      .set({ deletedAt: null })
      .where(eq(outfits.id, id))
      .returning();
    return restored;
  }

  async cleanupOldDeletedOutfits(): Promise<void> {
    // Delete outfits that were soft deleted over 30 days ago
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    await db
      .delete(outfits)
      .where(and(
        isNotNull(outfits.deletedAt),
        lt(outfits.deletedAt, thirtyDaysAgo)
      ));
  }

  async toggleFavoriteOutfit(id: string): Promise<Outfit> {
    const [outfit] = await db.select().from(outfits).where(eq(outfits.id, id));
    const [updated] = await db
      .update(outfits)
      .set({ isFavorite: !outfit.isFavorite })
      .where(eq(outfits.id, id))
      .returning();
    return updated;
  }

  // Collection operations
  async getUserCollections(userId: string): Promise<StyleCollection[]> {
    return await db
      .select()
      .from(styleCollections)
      .where(eq(styleCollections.userId, userId))
      .orderBy(desc(styleCollections.createdAt));
  }

  async createCollection(collection: InsertCollection): Promise<StyleCollection> {
    const [created] = await db
      .insert(styleCollections)
      .values(collection)
      .returning();
    return created;
  }

  async updateCollection(id: string, updates: Partial<InsertCollection>): Promise<StyleCollection> {
    const [updated] = await db
      .update(styleCollections)
      .set(updates)
      .where(eq(styleCollections.id, id))
      .returning();
    return updated;
  }

  async deleteCollection(id: string): Promise<void> {
    await db.delete(styleCollections).where(eq(styleCollections.id, id));
  }

  // Points operations
  async getUserPoints(userId: string): Promise<UserPoints | undefined> {
    const [points] = await db
      .select()
      .from(userPoints)
      .where(eq(userPoints.userId, userId));
    return points;
  }

  async updateUserPoints(userId: string, pointsToAdd: number): Promise<UserPoints> {
    const existing = await this.getUserPoints(userId);

    if (existing) {
      const newPoints = (existing.points ?? 0) + pointsToAdd;
      const newTotal = (existing.totalEarned ?? 0) + pointsToAdd;
      let newLevel = existing.level;

      // Level progression
      if (newTotal >= 10000) newLevel = "Expert";
      else if (newTotal >= 5000) newLevel = "Advanced";
      else if (newTotal >= 1000) newLevel = "Intermediate";

      const [updated] = await db
        .update(userPoints)
        .set({
          points: newPoints,
          totalEarned: newTotal,
          level: newLevel,
          updatedAt: new Date(),
        })
        .where(eq(userPoints.userId, userId))
        .returning();
      return updated;
    } else {
      return await this.initializeUserPoints(userId);
    }
  }

  async initializeUserPoints(userId: string): Promise<UserPoints> {
    const [created] = await db
      .insert(userPoints)
      .values({
        userId,
        points: 100, // Welcome bonus
        totalEarned: 100,
        level: "Beginner",
      })
      .returning();
    return created;
  }

  // Shopping analytics operations
  async trackShoppingClick(analytics: InsertShoppingAnalytics): Promise<ShoppingAnalytics> {
    const [created] = await db
      .insert(shoppingAnalytics)
      .values(analytics)
      .returning();
    return created;
  }

  // Admin operations
  async getAllUsers(): Promise<User[]> {
    return await db
      .select()
      .from(users)
      .orderBy(desc(users.createdAt));
  }

  async getAllOutfits(): Promise<Outfit[]> {
    return await db
      .select()
      .from(outfits)
      .orderBy(desc(outfits.createdAt));
  }

  async getAdminStats(): Promise<any> {
    const totalUsers = await db.select().from(users);
    const totalOutfits = await db.select().from(outfits);
    const premiumUsers = totalUsers.filter(u => u.subscriptionStatus && u.subscriptionStatus !== 'free');

    return {
      totalUsers: totalUsers.length,
      totalOutfits: totalOutfits.length,
      premiumUsers: premiumUsers.length,
      conversionRate: totalUsers.length > 0 ? (premiumUsers.length / totalUsers.length) * 100 : 0,
      estimatedRevenue: premiumUsers.length * 9.99
    };
  }
}

export const storage = new DatabaseStorage();

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

